import React from 'react';
import { View, Text, Image, ScrollView, TouchableOpacity, StyleSheet } from 'react-native';
import { colors } from '../theme/colors';
import Ionicons from 'react-native-vector-icons/Ionicons';

const HomeScreen = ({ navigation }) => {
  return (
    <ScrollView style={styles.container}>
      {/* Header */}
      <View style={styles.header}>
        <Text style={styles.title}>MAPA DE ELDEN RING</Text>
      </View>

      {/* Mapa Grande */}
      <Image 
        source={{ uri: 'data:image/jpeg;base64,' }} 
        style={styles.mapImage} 
      />

      {/* Luta dos Bosses */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>LUTA DOS BOSSES</Text>
        
        <View style={styles.bossesRow}>
          <TouchableOpacity 
            style={styles.bossCard}
            onPress={() => navigation.navigate('BossDetail', { bossName: 'Malenia' })}
          >
            <Image 
              source={{ uri: 'data:image/jpeg;base64,' }} 
              style={styles.bossImage} 
            />
          </TouchableOpacity>

          <TouchableOpacity 
            style={styles.bossCard}
            onPress={() => navigation.navigate('BossDetail', { bossName: 'Radahn' })}
          >
            <Image 
              source={{ uri: 'data:image/jpeg;base64,' }} 
              style={styles.bossImage} 
            />
          </TouchableOpacity>

          <TouchableOpacity 
            style={styles.bossCard}
            onPress={() => navigation.navigate('BossDetail', { bossName: 'Margitt' })}
          >
            <Image 
              source={{ uri: 'data:image/jpeg;base64,' }} 
              style={styles.bossImage} 
            />
          </TouchableOpacity>
        </View>
      </View>
    </ScrollView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.background,
  },
  header: {
    padding: 20,
    alignItems: 'center',
    backgroundColor: '#1a1a1a',
  },
  title: {
    fontSize: 24,
    color: colors.gold,
    fontWeight: 'bold',
  },
  mapImage: {
    width: '100%',
    height: 240,
    resizeMode: 'cover',
  },
  section: {
    padding: 20,
  },
  sectionTitle: {
    color: colors.gold,
    fontSize: 20,
    fontWeight: 'bold',
    marginBottom: 15,
  },
  bossesRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
  },
  bossCard: {
    width: '31%',
    borderRadius: 10,
    overflow: 'hidden',
    borderWidth: 2,
    borderColor: colors.gold,
  },
  bossImage: {
    width: '100%',
    height: 160,
    resizeMode: 'cover',
  },
});

export default HomeScreen;